API_name: nchu_course_get_detail
Description:
{
  "description": "依課程 ID 取得單門課程的詳細資訊與完整大綱。",
  "required_parameters": [
    {
      "name": "course_id",
      "type": "STRING",
      "description": "Course ID (選課號碼)"
    }
  ],
  "optional_parameters": [
    {
      "name": "include_syllabus",
      "type": "BOOLEAN",
      "description": "Include full syllabus content (課程簡述, 課程目標, 每週授課內容, 教學方法, 評量方法, etc.) (default: True)",
      "default": true
    },
    {
      "name": "semester",
      "type": "STRING",
      "description": "Semester code. If not specified, uses the latest semester.",
      "default": null
    }
  ]
}

